import React from 'react';

const Cultura = ({ sitios }) => {
    return (
        <div className="App"> {/* Esta clase centra todo y da margen */}
            <h1>Explora la Cultura de La Paz</h1>
            
            <div className="grid-container"> {/* Esta clase organiza las tarjetas */}
                {sitios && sitios.length > 0 ? (
                    sitios.map((sitio) => (
                        <div key={sitio.id_sitio} className="card"> {/* Estilo de tarjeta profesional */}
                            <h2>{sitio.nombre}</h2>
                            <p>{sitio.descripcion}</p>
                            <hr />
                            <small>📍 {sitio.direccion}</small>
                        </div>
                    ))
                ) : (
                    <div className="no-data">
                        <h3>Cargando información...</h3>
                        <p>Si esto tarda mucho, verifica que tu base de datos tenga datos.</p>
                    </div>
                )}
            </div>
        </div>
    );
};

export default Cultura;
